    // Therefore, if we can cyclically shift a subarray of length k arbitrarily, we can sort that subarray
    // if and only if the elements within that subarray are *the correct* set of elements that belong
    // to those positions in the final sorted array, AND those elements can be ordered correctly.

    // Crucial insight from similar problems: If a contiguous segment of length k can be sorted by 
    // arbitrary cyclic shifts, it means the set of elements in that segment must be identical 
    // to the set of elements in the corresponding segment of the fully sorted array. 
    // Since cyclic shifts can achieve any permutation of the *positions* of the elements within 
    // that segment, if the elements are distinct, we can sort them perfectly *within that segment*.

    // If the elements in the subarray are not all distinct, it might still be sortable.
    // Example: [2, 2, 1] -> Sorted: [1, 2, 2]. If k=3, we can sort it.

    // Conclusion: If we have a subarray of length k, and we can cyclically shift it, we can arrange its 
    // elements in *any* order. (Proof: A single cycle of length k generates S_k if we can choose the 
    // starting point, but here we have fixed positions and we apply cyclic shifts. A cyclic shift only 
    // permutes the elements cyclically. However, if we can shift left/right *arbitrarily* (multiple times), 
    // we can place any element at any position *within that subarray*. E.g., to move element at i to j, 
    // we shift left (i-j) times if i>j, or right (j-i) times if j>i, all modulo k).

    // So, the condition simplifies: For a factor k of n, we divide nums into n/k blocks of size k. 
    // Each block must be internally sortable, AND the blocks must appear in the correct sorted order.

    const factors = [];
    for (let i = 1; i * i <= n; i++) {
        if (n % i === 0) {
            factors.push(i);
            if (i * i !== n) {
                factors.push(n / i);
            }
        }
    }

    let totalSum = 0;

    for (const k of factors) {
        let isSortable = true;
        const numBlocks = n / k;

        // Check the condition for each block
        for (let b = 0; b < numBlocks; b++) {
            const start = b * k;
            const end = start + k;

            // Extract the current block
            const currentBlock = nums.slice(start, end);

            // Extract the target block from the fully sorted array
            const targetBlock = sortedNums.slice(start, end);

            // Condition 1: The set of elements in the current block must match the set of elements 
            // in the corresponding target block. Since we only allow internal permutation (cyclic shift),
            // the multiset of elements must be the same.
            const sortedCurrentBlock = [...currentBlock].sort((a, b) => a - b);

            if (JSON.stringify(sortedCurrentBlock) !== JSON.stringify(targetBlock)) {
                isSortable = false;
                break;
            }

            // Condition 2: Can we arrange the current block (which contains the correct set of elements)
            // into the target order using only cyclic shifts?

            // If we can achieve *any* permutation via cyclic shifts, then this is always true if the multisets match.
            // As established above, if we can apply arbitrary left/right cyclic shifts, we can achieve any 
            // permutation of the elements within that block.

            // Therefore, the only necessary and sufficient condition is that the multiset of elements 
            // in each block matches the multiset of elements in the corresponding block of the fully sorted array.
        }

        if (isSortable) {
            totalSum += k;
        }
    }

    return totalSum;
}
